import{_ as t,o as r,c as e,ai as l}from"./chunks/framework.ampVZV4B.js";const u=JSON.parse('{"title":"经典线上排查实战（CPU飙高与内存泄漏）","description":"","frontmatter":{},"headers":[],"relativePath":"network-linux/linux-troubleshooting.md","filePath":"network-linux/linux-troubleshooting.md"}'),n={name:"network-linux/linux-troubleshooting.md"};function i(s,o,a,c,g,p){return r(),e("div",null,[...o[0]||(o[0]=[l('<h1 id="经典线上排查实战-cpu飙高与内存泄漏" tabindex="-1">经典线上排查实战（CPU飙高与内存泄漏） <a class="header-anchor" href="#经典线上排查实战-cpu飙高与内存泄漏" aria-label="Permalink to “经典线上排查实战（CPU飙高与内存泄漏）”">​</a></h1><hr><h3 id="❓-面试官-如果线上系统突然变得非常卡-接口响应极慢-你作为后端主程该怎么排查处理-线上-cpu-飙高排查实战" tabindex="-1">❓ 面试官：如果线上系统突然变得非常卡，接口响应极慢，你作为后端主程该怎么排查处理？（线上 CPU 飙高排查实战） <a class="header-anchor" href="#❓-面试官-如果线上系统突然变得非常卡-接口响应极慢-你作为后端主程该怎么排查处理-线上-cpu-飙高排查实战" aria-label="Permalink to “❓ 面试官：如果线上系统突然变得非常卡，接口响应极慢，你作为后端主程该怎么排查处理？（线上 CPU 飙高排查实战）”">​</a></h3><p><em>频率：🔥🔥🔥🔥🔥</em></p><blockquote><p>这是考核候选人是否有过真实生产环境维护经验的试金石问题。</p></blockquote><p><strong>💡 一句话总结（先抛结论）：</strong> 遇到这种紧急情况，排查思路分为四步：<strong>看大盘（找异常节点） -&gt; 找耗性能进程（PID） -&gt; 找元凶线程（TID） -&gt; jstack 抓取堆栈定位具体代码行。</strong></p><p><strong>📝 详细的四步排查大法（面试高分剧本）：</strong></p><p><strong>第一步：找元凶进程（PID）</strong></p><ul><li>登录出现告警的服务器，敲 <code>top</code> 命令，看系统资源大盘。</li><li>如果 <code>load average</code>（系统负载）很高，并且列表里有一个 Java 进程（比如 Tomcat 或者是我们的 SpringBoot jar 包进程）的 CPU 占用率达到了 100% 甚至更多。</li><li>记下它的进程 ID（假设 PID = <code>1001</code>）。</li></ul><p><strong>第二步：找元凶线程（TID）</strong></p><ul><li>既然是 Java 进程占用过高，那肯定是进程里面的某一个线程在作怪（比如死循环）。</li><li>敲 <code>top -Hp 1001</code>。这会展示出进程 <code>1001</code> 下面的所有线程的资源占用排行。</li><li>找到消耗 CPU 最高的那个线程，记下它的线程 ID（假设 TID = <code>1010</code>）。</li></ul><p><strong>第三步：将 TID 转成十六进制</strong></p><ul><li>因为 JVM 打印的堆栈信息里，线程 ID 是用十六进制表示的，我们需要转换一下。</li><li>用命令 <code>printf &quot;%x\\n&quot; 1010</code> 把十进制的 1010 转成十六进制，得到 <code>3f2</code>。</li></ul><p><strong>第四步：通过 jstack 定位死循环代码</strong></p><ul><li>最关键的一步来了！敲 <code>jstack 1001 | grep -A 20 &#39;3f2&#39;</code>（把进程栈导出来，并在里面过滤寻找这个十六进制的线程 ID，显示前后 20 行代码调用信息）。</li><li><strong>结果：</strong> 这时候控制台上就会清晰地打印出这个疯狂占用 CPU 的线程<strong>正在执行哪个类的哪一行代码</strong>。</li></ul><p><strong>🔥 常见场景（追问加分项）：</strong> &quot;面试官，根据我的实战经验，定位到代码行后，通常是这两种情况导致 CPU 飙高：&quot;</p><ol><li><strong>业务死循环或复杂计算</strong>：比如某一段 <code>while(true)</code> 的退出的条件没写对，导致死循环；或者是写了一个极其复杂的正则表达式去解析长文本，发生了“正则回溯”导致 CPU 打满。修复代码重启即可。</li><li><strong>频繁 Full GC</strong>：如果定位到的线程是 <code>GC Task Thread</code>，那说明 CPU 飙高只是表象，真实情况是<strong>内存快撑爆了</strong>。JVM 在疯狂地执行垃圾回收企图清理内存，但每次只能回收一点点，导致陷入 <code>GC 停顿 -&gt; 应用变卡 -&gt; 继续 GC</code> 的死亡循环。这时候的排查方向就要从 CPU 转向排查 OOM（内存溢出）了。</li></ol><hr><h3 id="❓-面试官-线上系统报错-java-lang-outofmemoryerror-oom-服务直接挂了-你是怎么排查的" tabindex="-1">❓ 面试官：线上系统报错 java.lang.OutOfMemoryError（OOM），服务直接挂了，你是怎么排查的？ <a class="header-anchor" href="#❓-面试官-线上系统报错-java-lang-outofmemoryerror-oom-服务直接挂了-你是怎么排查的" aria-label="Permalink to “❓ 面试官：线上系统报错 java.lang.OutOfMemoryError（OOM），服务直接挂了，你是怎么排查的？”">​</a></h3><p><em>频率：🔥🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> OOM 发生时绝对不能靠猜。核心手段是<strong>获取系统崩溃瞬间的 Heap Dump（堆内存快照）文件</strong>，然后利用可视化分析工具（如 Eclipse MAT）顺藤摸瓜，找出是哪个大对象把内存撑爆了。</p><p><strong>📝 详细排查实战流程：</strong></p><ol><li><p><strong>事前防御：开启自动 Dump（必须要有）</strong></p><ul><li>&quot;在我的项目中，Java 启动脚本里一定会加上这几个参数： <code>-XX:+HeapDumpOnOutOfMemoryError</code>（发生 OOM 时自动生成 dump 文件） <code>-XX:HeapDumpPath=/data/log/heapdump.hprof</code>（指定快照生成的路径）。&quot;</li><li>如果没有配置这些，进程 OOM 挂掉后现场就完全丢失了，排查难度极大。</li></ul></li><li><p><strong>事发取证</strong></p><ul><li>发生 OOM 报警后，去服务器指定的目录下，把那个几百兆甚至几 GB 的 <code>.hprof</code> 快照文件下载到本地电脑进行分析。</li></ul></li><li><p><strong>事后分析（使用 MAT）</strong></p><ul><li>打开 Eclipse MAT（Memory Analyzer Tool）加载快照文件。</li><li>第一眼看它自动生成的 <strong>&quot;Leak Suspects&quot;（泄漏嫌疑人报告）</strong>。它会用一个很直观的大饼图告诉你问题出在哪。比如：&quot;有一个 <code>ArrayList</code> 占据了系统 85% 的内存，里面装了 200 万个 <code>UserEntity</code> 对象&quot;。</li><li>然后点击 &quot;Path to GC Roots&quot;（查看到达 GC Root 的强引用链），就能看到是谁在持有这个 List 并且不释放。</li></ul></li><li><p><strong>定位与总结（常见 OOM 原因剖析）</strong></p><ul><li>通过引用链，最后能精确定位到是哪一个 Controller 或 Service 中的代码。</li><li><strong>典型的故障场景分享</strong>： <ul><li><strong>场景 A（大对象/无分页）</strong>：同事写的一段查询代码 <code>select * from user</code> 忘了加 <code>limit</code> 分页条件。恰好表里有几百万条数据，一次性全部加载到内存里转换成 List，瞬间就把堆内存撑爆了。<strong>解决：强制要求所有批量查询必须分页。</strong></li><li><strong>场景 B（内存泄漏/ThreadLocal）</strong>：用了一个全局的静态 Map 或者 <code>ThreadLocal</code> 缓存数据，但是每次用完<strong>忘记执行 remove() 清理</strong>。对象用完了却一直被强引用着无法回收，时间一长，内存就渐渐满了直到 OOM。<strong>解决：规范代码，确保 try-finally 块里执行清理逻辑。</strong></li><li><strong>场景 C（流未关闭）</strong>：频繁进行 Excel 导出或者大文件上传下载，没处理好流的关闭。</li></ul></li></ul></li></ol>',23)])])}const m=t(n,[["render",i]]);export{u as __pageData,m as default};
